namespace TestProject {
    public class Program {
        public static void Main(string[] args) {
            var builder = WebApplication.CreateBuilder(args);

            // Add services to the container.

            builder.Services.AddControllers();

            // Bind the FileService configuration section and register the
            // path-safe IFileService implementation so controllers can be
            // activated through dependency injection.
            builder.Services.Configure<TestProject.Configuration.FileServiceOptions>(
                builder.Configuration.GetSection("FileService"));
            builder.Services.AddSingleton<TestProject.Services.IFileService, TestProject.Services.FileService>();

            var app = builder.Build();

            // Configure the HTTP request pipeline.

            app.UseHttpsRedirection();

            app.UseDefaultFiles();

            app.UseStaticFiles();

            app.MapControllers();

            app.MapFallbackToFile("index.html");

            app.Run();
        }
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.StaticFiles;
using TestProject.Models;
using TestProject.Services;

namespace TestProject.Controllers;

/// <summary>
/// HTTP API surface for the path-safe file system operations exposed by
/// <see cref="IFileService"/>. Every endpoint is rooted under
/// <c>/api/files</c> and delegates its work to <see cref="Execute"/> (or
/// <see cref="ExecuteAsync"/> for the async <see cref="Upload"/> endpoint),
/// which translates the well-known file system faults
/// (<see cref="ArgumentException"/>, <see cref="UnauthorizedAccessException"/>,
/// <see cref="DirectoryNotFoundException"/>, <see cref="FileNotFoundException"/>
/// and <see cref="IOException"/>) into a <c>400 Bad Request</c> carrying the
/// exception message, leaving any other exception type to propagate.
/// </summary>
[ApiController]
[Route("api/[controller]")]
public class FilesController : ControllerBase
{
    private readonly IFileService _service;
    private static readonly FileExtensionContentTypeProvider ContentTypeProvider = new();

    /// <summary>
    /// Creates a new <see cref="FilesController"/> bound to the supplied
    /// <paramref name="service"/>.
    /// </summary>
    public FilesController(IFileService service)
    {
        _service = service;
    }

    // =====================================================================
    // Browse
    // =====================================================================

    /// <summary>
    /// Lists the immediate children of the directory at <paramref name="path"/>
    /// (the root when omitted or empty), returning directories first then
    /// files, each group sorted by name.
    /// </summary>
    [HttpGet("browse")]
    public ActionResult<BrowseResultDto> Browse([FromQuery] string? path)
        => Execute(() => Ok(_service.Browse(path ?? string.Empty)));

    // =====================================================================
    // Search
    // =====================================================================

    /// <summary>
    /// Recursively searches under <paramref name="path"/> (the root when
    /// omitted or empty) for entries whose name contains <paramref name="query"/>
    /// (case-insensitive).
    /// </summary>
    [HttpGet("search")]
    public ActionResult<SearchResultDto> Search([FromQuery] string query, [FromQuery] string? path)
        => Execute(() => Ok(_service.Search(query ?? string.Empty, path ?? string.Empty)));

    // =====================================================================
    // Upload
    // =====================================================================

    /// <summary>
    /// Writes the uploaded <paramref name="file"/> into the directory at
    /// <paramref name="path"/> (the root when omitted or empty), creating it
    /// if necessary. The response reports the joined relative path of the
    /// stored file.
    /// </summary>
    [HttpPost("upload")]
    public async Task<IActionResult> Upload([FromQuery] string? path, [FromForm] IFormFile file)
        => await ExecuteAsync(async () =>
        {
            await _service.UploadAsync(path ?? string.Empty, file);
            var dir = NormalizeRelativePath(path ?? string.Empty);
            var resultPath = string.IsNullOrEmpty(dir) ? file.FileName : $"{dir}/{file.FileName}";
            return Ok(new { path = resultPath });
        });

    // =====================================================================
    // Download
    // =====================================================================

    /// <summary>
    /// Streams the file at <paramref name="path"/> as a physical file
    /// response, deriving the content type from the extension (defaulting to
    /// <c>application/octet-stream</c> when unknown).
    /// </summary>
    [HttpGet("download")]
    public IActionResult Download([FromQuery] string path)
        => Execute(() =>
        {
            var full = _service.ResolveFullPath(path);
            var contentType = ContentTypeProvider.TryGetContentType(full, out var ct)
                ? ct
                : "application/octet-stream";
            return PhysicalFile(full, contentType, Path.GetFileName(full));
        });

    // =====================================================================
    // Delete
    // =====================================================================

    /// <summary>
    /// Deletes the file or directory (recursively) at <paramref name="path"/>.
    /// </summary>
    [HttpDelete("delete")]
    public IActionResult Delete([FromQuery] string path)
        => Execute(() =>
        {
            _service.Delete(path);
            return Ok(new { success = true });
        });

    // =====================================================================
    // Move
    // =====================================================================

    /// <summary>
    /// Moves the file or directory at <paramref name="request"/>'s
    /// <see cref="MoveRequest.SourcePath"/> to its
    /// <see cref="MoveRequest.DestinationPath"/>.
    /// </summary>
    [HttpPost("move")]
    public IActionResult Move([FromBody] MoveRequest request)
        => Execute(() =>
        {
            _service.Move(request);
            return Ok(new { success = true });
        });

    // =====================================================================
    // Copy
    // =====================================================================

    /// <summary>
    /// Copies the file or directory at <paramref name="request"/>'s
    /// <see cref="CopyRequest.SourcePath"/> to its
    /// <see cref="CopyRequest.DestinationPath"/>.
    /// </summary>
    [HttpPost("copy")]
    public IActionResult Copy([FromBody] CopyRequest request)
        => Execute(() =>
        {
            _service.Copy(request);
            return Ok(new { success = true });
        });

    // =====================================================================
    // Helpers
    // =====================================================================

    /// <summary>
    /// Runs <paramref name="body"/> and translates the well-known file system
    /// faults (<see cref="ArgumentException"/>,
    /// <see cref="UnauthorizedAccessException"/>,
    /// <see cref="DirectoryNotFoundException"/>, <see cref="FileNotFoundException"/>
    /// and <see cref="IOException"/>) into a <c>400 Bad Request</c> carrying
    /// the exception message. Any other exception type propagates unchanged.
    /// </summary>
    /// <remarks>
    /// The return type is <see cref="ActionResult"/> (rather than
    /// <see cref="IActionResult"/>) so the same helper can back both the
    /// <see cref="Browse"/>/<see cref="Search"/> endpoints, whose return type
    /// is <c>ActionResult&lt;T&gt;</c>, and the plain
    /// <see cref="IActionResult"/> endpoints; <see cref="ActionResult"/>
    /// implements <see cref="IActionResult"/> and converts implicitly to
    /// <c>ActionResult&lt;T&gt;</c>, while <see cref="IActionResult"/> does not.
    /// </remarks>
    private ActionResult Execute(Func<ActionResult> body)
    {
        try
        {
            return body();
        }
        catch (ArgumentException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (UnauthorizedAccessException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (DirectoryNotFoundException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (FileNotFoundException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (IOException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
    }

    /// <summary>
    /// Async variant of <see cref="Execute"/> for endpoints that must await
    /// service calls (currently <see cref="Upload"/>). Same catch list and
    /// translation; non-translated exceptions propagate. The body is awaited
    /// (never unwrapped via <c>.Result</c>/<c>.Wait()</c>) so a faulting body
    /// surfaces its original exception rather than an
    /// <see cref="AggregateException"/>.
    /// </summary>
    private async Task<ActionResult> ExecuteAsync(Func<Task<ActionResult>> body)
    {
        try
        {
            return await body();
        }
        catch (ArgumentException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (UnauthorizedAccessException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (DirectoryNotFoundException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (FileNotFoundException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
        catch (IOException ex)
        {
            return BadRequest(new { error = ex.Message });
        }
    }

    /// <summary>
    /// Normalizes a raw directory path for use in the response: replaces
    /// backslashes with forward slashes, collapses repeated slashes, and
    /// removes <c>.</c> and <c>..</c> segments. Returns empty string when
    /// the path is null, empty, or collapses to nothing.
    /// </summary>
    private static string NormalizeRelativePath(string raw)
    {
        if (string.IsNullOrEmpty(raw))
            return string.Empty;

        return string.Join("/",
            raw.Replace('\\', '/')
               .Split('/')
               .Where(s => s.Length > 0 && s != "." && s != ".."));
    }
}

using System;
using System.IO;
using System.Text.RegularExpressions;
using Xunit;

namespace TestProject.Tests;

/// <summary>
/// Tests for the dependency-injection wiring and HTTP request-pipeline
/// ordering in <c>Program.cs</c>.
///
/// The application bootstrap is expected to:
/// <list type="bullet">
/// <item>Bind <see cref="TestProject.FileServiceOptions"/> from the
/// "FileService" configuration section via
/// <c>builder.Services.Configure&lt;FileServiceOptions&gt;(
/// builder.Configuration.GetSection("FileService"))</c>.</item>
/// <item>Register <see cref="TestProject.Services.IFileService"/> backed by
/// <see cref="TestProject.Services.FileService"/> as a singleton.</item>
/// <item>Configure the middleware pipeline in the exact order
/// <c>UseHttpsRedirection</c> -&gt; <c>UseDefaultFiles</c> -&gt;
/// <c>UseStaticFiles</c> -&gt; <c>MapControllers</c> -&gt;
/// <c>MapFallbackToFile("index.html")</c> -&gt; <c>Run</c>.</item>
/// </list>
///
/// These assertions parse the source of <c>Program.cs</c> directly so the
/// contract is locked in regardless of formatting choices (fully-qualified
/// names or added <c>using</c> directives). The file is located by walking up
/// from the test output directory to the folder that contains
/// <c>TestProject.csproj</c>.
/// </summary>
public class ProgramWiringTests
{
    private static readonly string ProgramSource = LoadProgramSource();

    private const string OptionsConfigurePattern =
        @"Services\s*\.\s*Configure\s*<[^>]*FileServiceOptions[^>]*>";

    private const string FileServiceSectionPattern =
        @"GetSection\s*\(\s*""FileService""\s*\)";

    private const string SingletonPattern =
        @"Services\s*\.\s*AddSingleton\s*<[^>]*IFileService[^>]*,\s*[^>]*FileService\s*>";

    private const string FallbackIndexHtmlPattern =
        @"MapFallbackToFile\s*\(\s*""index\.html""\s*\)";

    private const string RunPattern = @"\.\s*Run\s*\(\s*\)";

    /// <summary>
    /// Walks up from the test assembly output directory until it finds a
    /// folder containing both <c>TestProject.csproj</c> and <c>Program.cs</c>,
    /// then returns the Program.cs source text.
    /// </summary>
    private static string LoadProgramSource()
    {
        var dir = new DirectoryInfo(AppContext.BaseDirectory);
        while (dir is not null)
        {
            var csprojPath = Path.Combine(dir.FullName, "TestProject.csproj");
            if (File.Exists(csprojPath))
            {
                var programPath = Path.Combine(dir.FullName, "Program.cs");
                if (File.Exists(programPath))
                {
                    return File.ReadAllText(programPath);
                }
            }

            dir = dir.Parent;
        }

        throw new FileNotFoundException(
            "Could not locate Program.cs next to TestProject.csproj by walking up " +
            "from the test output directory (" + AppContext.BaseDirectory + ").");
    }

    /// <summary>Returns the index of the first match of <paramref name="pattern"/>,
    /// or -1 when it is absent.</summary>
    private static int IndexOf(string pattern)
    {
        var match = Regex.Match(ProgramSource, pattern);
        return match.Success ? match.Index : -1;
    }

    /// <summary>Returns the index of the first occurrence of a simple method
    /// call like <c>UseDefaultFiles(</c>, or -1 when absent.</summary>
    private static int CallIndex(string methodName) =>
        IndexOf(Regex.Escape(methodName) + @"\s*\(");

    /// <summary>Counts how many times <paramref name="pattern"/> matches.</summary>
    private static int Count(string pattern) =>
        Regex.Matches(ProgramSource, pattern).Count;

    private static void AssertPresent(string pattern, string description)
    {
        Assert.True(IndexOf(pattern) >= 0,
            $"Expected {description} to be present in Program.cs.");
    }

    private static void AssertCallOrder(string earlier, string later)
    {
        var earlierIdx = CallIndex(earlier);
        var laterIdx = CallIndex(later);

        Assert.True(earlierIdx >= 0, $"Expected '{earlier}(' in Program.cs.");
        Assert.True(laterIdx >= 0, $"Expected '{later}(' in Program.cs.");
        Assert.True(earlierIdx < laterIdx,
            $"'{earlier}' must appear before '{later}' in the Program.cs pipeline.");
    }

    // =====================================================================
    // Service registration: FileServiceOptions
    // =====================================================================

    [Fact]
    public void Program_Registers_FileServiceOptions_OnServicesCollection()
    {
        AssertPresent(OptionsConfigurePattern,
            "builder.Services.Configure<...FileServiceOptions>");
    }

    [Fact]
    public void Program_Registers_FileServiceOptions_FromFileServiceSection()
    {
        var configureIdx = IndexOf(OptionsConfigurePattern);
        var sectionIdx = IndexOf(FileServiceSectionPattern);

        Assert.True(sectionIdx >= 0,
            "Expected builder.Configuration.GetSection(\"FileService\") in Program.cs.");

        // The section should be supplied to the Configure call (i.e. it appears
        // right after the Configure<FileServiceOptions> token).
        Assert.True(configureIdx >= 0 && sectionIdx > configureIdx,
            "GetSection(\"FileService\") should be the argument passed to " +
            "Configure<FileServiceOptions>.");
        Assert.True(sectionIdx - configureIdx < 250,
            "GetSection(\"FileService\") should be supplied directly to the " +
            "Configure<FileServiceOptions>(...) call.");
    }

    [Fact]
    public void Program_Registers_FileServiceOptions_AfterAddControllers_AndBeforeBuild()
    {
        var addControllers = CallIndex("AddControllers");
        var configure = IndexOf(OptionsConfigurePattern);
        var build = IndexOf(@"\.\s*Build\s*\(\s*\)");

        Assert.True(addControllers >= 0 && configure > addControllers,
            "Configure<FileServiceOptions> must be added after AddControllers().");
        Assert.True(build < 0 || configure < build,
            "Configure<FileServiceOptions> must be added before builder.Build().");
    }

    // =====================================================================
    // Service registration: IFileService -> FileService singleton
    // =====================================================================

    [Fact]
    public void Program_Registers_IFileService_AsSingleton_FileService()
    {
        AssertPresent(SingletonPattern,
            "builder.Services.AddSingleton<...IFileService..., ...FileService>()");
    }

    [Fact]
    public void Program_Registers_IFileService_AsSingleton_ExactlyOnce()
    {
        Assert.Equal(1, Count(SingletonPattern));
    }

    [Fact]
    public void Program_Registers_IFileService_AfterAddControllers_AndBeforeBuild()
    {
        var addControllers = CallIndex("AddControllers");
        var singleton = IndexOf(SingletonPattern);
        var build = IndexOf(@"\.\s*Build\s*\(\s*\)");

        Assert.True(addControllers >= 0 && singleton > addControllers,
            "AddSingleton<IFileService, FileService> must be added after AddControllers().");
        Assert.True(build < 0 || singleton < build,
            "AddSingleton<IFileService, FileService> must be added before builder.Build().");
    }

    [Fact]
    public void Program_Registers_Options_BeforeIFileService()
    {
        var configure = IndexOf(OptionsConfigurePattern);
        var singleton = IndexOf(SingletonPattern);

        Assert.True(configure >= 0 && singleton >= 0 && configure < singleton,
            "FileServiceOptions should be configured before the FileService singleton " +
            "that depends on them is registered.");
    }

    // =====================================================================
    // Pipeline statements are present exactly once
    // =====================================================================

    [Fact]
    public void Program_Pipeline_UsesHttpsRedirection_ExactlyOnce()
    {
        Assert.Equal(1, Count(@"UseHttpsRedirection\s*\("));
    }

    [Fact]
    public void Program_Pipeline_UsesDefaultFiles_ExactlyOnce()
    {
        Assert.Equal(1, Count(@"UseDefaultFiles\s*\("));
    }

    [Fact]
    public void Program_Pipeline_UsesStaticFiles_ExactlyOnce()
    {
        Assert.Equal(1, Count(@"UseStaticFiles\s*\("));
    }

    [Fact]
    public void Program_Pipeline_MapsControllers_ExactlyOnce()
    {
        Assert.Equal(1, Count(@"MapControllers\s*\("));
    }

    [Fact]
    public void Program_Pipeline_MapsFallbackToIndexHtml_ExactlyOnce()
    {
        Assert.Equal(1, Count(FallbackIndexHtmlPattern));
    }

    // =====================================================================
    // Pipeline ordering
    // =====================================================================

    [Fact]
    public void Program_Pipeline_HttpsRedirection_ComesBeforeDefaultFiles()
    {
        AssertCallOrder("UseHttpsRedirection", "UseDefaultFiles");
    }

    [Fact]
    public void Program_Pipeline_DefaultFiles_ComesBeforeStaticFiles()
    {
        // DefaultFiles MUST run before StaticFiles so that requests for "/"
        // are rewritten to index.html before the static file middleware looks
        // for them.
        AssertCallOrder("UseDefaultFiles", "UseStaticFiles");
    }

    [Fact]
    public void Program_Pipeline_StaticFiles_ComesBeforeMapControllers()
    {
        AssertCallOrder("UseStaticFiles", "MapControllers");
    }

    [Fact]
    public void Program_Pipeline_MapControllers_ComesBeforeFallback()
    {
        var controllers = CallIndex("MapControllers");
        var fallback = IndexOf(FallbackIndexHtmlPattern);

        Assert.True(controllers >= 0, "Expected 'MapControllers(' in Program.cs.");
        Assert.True(fallback >= 0, "Expected MapFallbackToFile(\"index.html\") in Program.cs.");
        Assert.True(controllers < fallback,
            "MapControllers must come before MapFallbackToFile so that API routes " +
            "take precedence over the SPA fallback.");
    }

    [Fact]
    public void Program_Pipeline_Fallback_ComesBeforeRun()
    {
        var fallback = IndexOf(FallbackIndexHtmlPattern);
        var run = IndexOf(RunPattern);

        Assert.True(fallback >= 0, "Expected MapFallbackToFile(\"index.html\") in Program.cs.");
        Assert.True(run >= 0, "Expected app.Run() in Program.cs.");
        Assert.True(fallback < run,
            "MapFallbackToFile must be registered before app.Run().");
    }

    [Fact]
    public void Program_Pipeline_Build_ComesBeforeAnyMiddleware()
    {
        var build = IndexOf(@"\.\s*Build\s*\(\s*\)");
        var https = CallIndex("UseHttpsRedirection");

        Assert.True(build >= 0, "Expected builder.Build() in Program.cs.");
        Assert.True(https >= 0, "Expected UseHttpsRedirection() in Program.cs.");
        Assert.True(build < https,
            "builder.Build() must occur before the request pipeline is configured.");
    }

    [Fact]
    public void Program_Pipeline_FullOrder_IsHttpsRedirection_DefaultFiles_StaticFiles_MapControllers_Fallback_Run()
    {
        var https = CallIndex("UseHttpsRedirection");
        var defaults = CallIndex("UseDefaultFiles");
        var stat = CallIndex("UseStaticFiles");
        var controllers = CallIndex("MapControllers");
        var fallback = IndexOf(FallbackIndexHtmlPattern);
        var run = IndexOf(RunPattern);

        Assert.True(https >= 0 && defaults >= 0 && stat >= 0 &&
                    controllers >= 0 && fallback >= 0 && run >= 0,
            "All six expected pipeline statements must be present in Program.cs.");

        Assert.True(https < defaults,
            "Order: UseHttpsRedirection must precede UseDefaultFiles.");
        Assert.True(defaults < stat,
            "Order: UseDefaultFiles must precede UseStaticFiles.");
        Assert.True(stat < controllers,
            "Order: UseStaticFiles must precede MapControllers.");
        Assert.True(controllers < fallback,
            "Order: MapControllers must precede MapFallbackToFile.");
        Assert.True(fallback < run,
            "Order: MapFallbackToFile must precede Run.");
    }

    // =====================================================================
    // End-to-end ordering of service registration vs. pipeline
    // =====================================================================

    [Fact]
    public void Program_AllServiceRegistrations_HappenBeforeAnyMiddleware()
    {
        var lastRegistration = Math.Max(
            IndexOf(OptionsConfigurePattern),
            IndexOf(SingletonPattern));
        var firstMiddleware = CallIndex("UseHttpsRedirection");

        Assert.True(lastRegistration >= 0 && firstMiddleware >= 0,
            "Expected both service registrations and pipeline middleware in Program.cs.");
        Assert.True(lastRegistration < firstMiddleware,
            "All DI registrations must occur before the HTTP pipeline is configured.");
    }
}

using System.Reflection;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Infrastructure;
using TestProject.Controllers;
using TestProject.Models;
using TestProject.Services;
using TestProject.Tests.TestHelpers;
using Xunit;

namespace TestProject.Tests.Controllers;

/// <summary>
/// Behavioral tests for <see cref="FilesController"/>. Each test drives the
/// controller with a configurable <see cref="FakeFileService"/> and asserts
/// on the returned <see cref="IActionResult"/>: the happy paths verify that
/// the service is invoked with the normalized inputs and that the response
/// payload has the documented shape, while the error paths verify that the
/// five catch-and-translate exception types yield a 400 with the message.
///
/// The controller is exercised directly (not through the ASP.NET Core
/// pipeline) so model-binding attributes like <c>[FromQuery]</c> are not
/// applied; arguments are passed as ordinary method parameters.
/// </summary>
public class FilesControllerTests
{
    /// <summary>
    /// The five exception types the controller must catch and translate into
    /// a <c>BadRequest</c>. Note <see cref="DirectoryNotFoundException"/> and
    /// <see cref="FileNotFoundException"/> are <see cref="IOException"/>
    /// subtypes, but are enumerated explicitly to match the documented
    /// catch list.
    /// </summary>
    public static IEnumerable<object[]> CaughtExceptions()
    {
        // The five exception types the controller documents and catches by
        // name. Each must map to a 400 carrying its Message.
        yield return new object[] { new ArgumentException("arg-message") };
        yield return new object[] { new UnauthorizedAccessException("unauth-message") };
        yield return new object[] { new DirectoryNotFoundException("dir-message") };
        yield return new object[] { new FileNotFoundException("file-message") };
        yield return new object[] { new IOException("io-message") };

        // Subtypes that must be caught by virtue of inheritance. The catch
        // list names base types (ArgumentException, IOException), so derived
        // exceptions must ALSO resolve to 400. A refactor that switched to
        // exact-type matching (e.g. `switch (ex.GetType())`) would let these
        // leak through as unhandled — these cases pin the inheritance-based
        // contract that the extracted helper must preserve.
        yield return new object[] { new ArgumentNullException("p", "argnull-message") };
        yield return new object[] { new ArgumentOutOfRangeException("p", "argoor-message") };
        yield return new object[] { new PathTooLongException("pathtoolong-message") };
    }

    private static FilesController CreateController(FakeFileService service)
    {
        return new FilesController(service);
    }

    private static object? GetProperty(object instance, string name)
    {
        var property = instance.GetType().GetProperty(name);
        Assert.NotNull(property);
        return property!.GetValue(instance);
    }

    /// <summary>
    /// Asserts that <paramref name="value"/> exposes exactly one public
    /// property, named <paramref name="expectedName"/>, and returns it for
    /// further type/value assertions. Used to pin the *exact* payload shape
    /// of the Ok/BadRequest anonymous bodies so a refactor cannot silently
    /// add, rename, drop, or retyped a field.
    /// </summary>
    private static PropertyInfo AssertSingleProperty(object value, string expectedName)
    {
        var property = Assert.Single(value.GetType().GetProperties());
        Assert.Equal(expectedName, property.Name);
        return property;
    }

    // =====================================================================
    // Browse
    // =====================================================================

    [Fact]
    public void Browse_ReturnsOk200_WithServiceResult()
    {
        var dto = new BrowseResultDto("docs", "", Array.Empty<FileEntryDto>(), 0, 0, 0L);
        var fake = new FakeFileService { BrowseResult = dto };
        var controller = CreateController(fake);

        var actionResult = controller.Browse("docs");

        var ok = Assert.IsType<OkObjectResult>(actionResult.Result);
        Assert.Equal(StatusCodes.Status200OK, ok.StatusCode);
        Assert.Same(dto, ok.Value);
    }

    [Fact]
    public void Browse_PassesProvidedPathToService()
    {
        var fake = new FakeFileService();
        var controller = CreateController(fake);

        controller.Browse("docs/sub");

        Assert.Equal("docs/sub", fake.BrowsePath);
    }

    [Theory]
    [InlineData(null)]
    [InlineData("")]
    public void Browse_PassesEmptyString_WhenPathIsNullOrEmpty(string? path)
    {
        var fake = new FakeFileService();
        var controller = CreateController(fake);

        controller.Browse(path);

        Assert.Equal(string.Empty, fake.BrowsePath);
    }

    [Theory]
    [MemberData(nameof(CaughtExceptions))]
    public void Browse_WhenServiceThrows_ReturnsBadRequest400_WithErrorMessage(Exception ex)
    {
        var fake = new FakeFileService { BrowseException = ex };
        var controller = CreateController(fake);

        var actionResult = controller.Browse("any");

        var badRequest = Assert.IsType<BadRequestObjectResult>(actionResult.Result);
        Assert.Equal(StatusCodes.Status400BadRequest, badRequest.StatusCode);
        Assert.Equal(ex.Message, GetProperty(badRequest.Value!, "error"));
    }

    // =====================================================================
    // Search
    // =====================================================================

    [Fact]
    public void Search_ReturnsOk200_WithServiceResult()
    {
        var dto = new SearchResultDto("report", "docs", Array.Empty<FileEntryDto>());
        var fake = new FakeFileService { SearchResult = dto };
        var controller = CreateController(fake);

        var actionResult = controller.Search("report", "docs");

        var ok = Assert.IsType<OkObjectResult>(actionResult.Result);
        Assert.Equal(StatusCodes.Status200OK, ok.StatusCode);
        Assert.Same(dto, ok.Value);
    }

    [Fact]
    public void Search_PassesQueryAndPathToService()
    {
        var fake = new FakeFileService();
        var controller = CreateController(fake);

