using System.IO;
using System.Reflection;

namespace TestProject.Tests.TestHelpers;

/// <summary>
/// Locates and reads source files that live next to the application project
/// (e.g. <c>Program.cs</c>, <c>Controllers/FilesController.cs</c>,
/// <c>README.md</c>) from within a test running out of the compiled
/// <c>bin/Debug/...</c> output directory.
///
/// <para>
/// The root is discovered by walking up from
/// <see cref="AppContext.BaseDirectory"/> until a directory containing
/// <c>TestProject.csproj</c> is found. A relative path is then resolved
/// against that root. This mirrors the approach already used by
/// <c>ProgramWiringTests.LoadProgramSource</c> but is shared/reusable so
/// security wiring tests, controller doc-comment tests and README tests do
/// not each reimplement the directory walk.
/// </para>
/// </summary>
public static class SourceFileLoader
{
    /// <summary>
    /// Returns the directory containing <c>TestProject.csproj</c>, found by
    /// walking up from the test assembly's output directory. Throws if it
    /// cannot be located.
    /// </summary>
    public static string FindProjectRoot()
    {
        var dir = new DirectoryInfo(AppContext.BaseDirectory);
        while (dir is not null)
        {
            if (File.Exists(Path.Combine(dir.FullName, "TestProject.csproj")))
            {
                return dir.FullName;
            }

            dir = dir.Parent;
        }

        throw new FileNotFoundException(
            "Could not locate the project root (folder containing TestProject.csproj) " +
            "by walking up from the test output directory (" + AppContext.BaseDirectory + ").");
    }

    /// <summary>
    /// Loads the source file at <paramref name="relativeSegments"/> relative
    /// to the project root (the folder containing <c>TestProject.csproj</c>).
    /// Throws with a descriptive message if the file is not found.
    /// </summary>
    /// <param name="relativeSegments">
    /// The path parts under the project root, e.g.
    /// <c>("Controllers", "FilesController.cs")</c> or
    /// <c>("Program.cs",)</c> or <c>("README.md",)</c>.</param>
    public static string LoadAdjacent(params string[] relativeSegments)
    {
        var root = FindProjectRoot();
        var fullPath = Path.Combine(root, Path.Combine(relativeSegments));

        if (!File.Exists(fullPath))
        {
            throw new FileNotFoundException(
                $"Expected source file not found at '{fullPath}' (resolved from project " +
                $"root '{root}').", fullPath);
        }

        return File.ReadAllText(fullPath);
    }
}

using System.IO;
using System.Text.RegularExpressions;
using TestProject.Tests.TestHelpers;
using Xunit;

namespace TestProject.Tests;

/// <summary>
/// Security wiring tests for the HTTP request pipeline and DI registrations
/// in <c>Program.cs</c>.
///
/// <para>
/// <c>[Authorize]</c> on <see cref="TestProject.Controllers.FilesController"/>
/// is only effective when the ASP.NET Core authentication/authorization
/// infrastructure is actually wired into the host: the services must be
/// registered before <c>builder.Build()</c> and the two middlewares must run
/// in the request pipeline in the correct order before the endpoints are
/// mapped. Without any of these, an unauthenticated request to
/// <c>/api/files/*</c> still succeeds, so the file-management surface stays
/// open exactly as the security finding describes.
/// </para>
///
/// <para>
/// These tests assert the presence, count and relative ordering of the
/// authentication/authorization calls by parsing the source of
/// <c>Program.cs</c> directly — the same strategy used by
/// <see cref="ProgramWiringTests"/> — so the contract is locked in regardless
/// of formatting choices.
/// </para>
///
/// The required contract (the preferred fix):
/// <list type="bullet">
/// <item><c>AddAuthentication(...)</c> is registered on the services
/// collection, chained to a scheme handler (<c>.AddCookie</c> or
/// <c>.AddJwtBearer</c>).</item>
/// <item><c>AddAuthorization()</c> is registered on the services
/// collection.</item>
/// <item>Both registrations occur before <c>builder.Build()</c>.</item>
/// <item><c>UseAuthentication()</c> and <c>UseAuthorization()</c> are each
/// present exactly once in the pipeline.</item>
/// <item><c>UseAuthentication()</c> precedes <c>UseAuthorization()</c>
/// (the principal must be established before it is authorized).</item>
/// <item><c>UseAuthorization()</c> precedes <c>MapControllers()</c> (so the
/// <c>[Authorize]</c> attribute is enforced on every routed endpoint).</item>
/// <item><c>UseAuthorization()</c> precedes the SPA fallback and
/// <c>app.Run()</c>.</item>
/// </list>
/// </summary>
public class ProgramSecurityWiringTests
{
    private static readonly string ProgramSource = SourceFileLoader.LoadAdjacent("Program.cs");

    // Authentication/authorization must not be left at the framework default
    // (open). Pin each required call.

    private const string AddAuthenticationPattern = @"AddAuthentication\s*\(";
    private const string AddAuthorizationPattern = @"AddAuthorization\s*\(";
    private const string UseAuthenticationPattern = @"UseAuthentication\s*\(";
    private const string UseAuthorizationPattern = @"UseAuthorization\s*\(";

    private const string MapControllersPattern = @"MapControllers\s*\(";
    private const string FallbackIndexHtmlPattern =
        @"MapFallbackToFile\s*\(\s*""index\.html""\s*\)";
    private const string RunPattern = @"\.\s*Run\s*\(\s*\)";
    private const string BuildPattern = @"\.\s*Build\s*\(\s*\)";

    private const string CookieSchemePattern = @"\.AddCookie\s*\(";
    private const string JwtSchemePattern = @"\.AddJwtBearer\s*\(";

    /// <summary>Returns the index of the first match of <paramref name="pattern"/>,
    /// or -1 when it is absent.</summary>
    private static int IndexOf(string pattern)
    {
        var match = Regex.Match(ProgramSource, pattern);
        return match.Success ? match.Index : -1;
    }

    /// <summary>Counts how many times <paramref name="pattern"/> matches.</summary>
    private static int Count(string pattern) =>
        Regex.Matches(ProgramSource, pattern).Count;

    private static void AssertPresent(string pattern, string description)
    {
        Assert.True(IndexOf(pattern) >= 0,
            $"Expected {description} to be present in Program.cs so the " +
            "/api/files/* surface is access-controlled.");
    }

    // =====================================================================
    // Service registration: authentication
    // =====================================================================

    [Fact]
    public void Program_RegistersAuthentication_OnServicesCollection()
    {
        AssertPresent(AddAuthenticationPattern, "AddAuthentication(...)");
    }

    [Fact]
    public void Program_RegistersAuthentication_BeforeBuild()
    {
        var auth = IndexOf(AddAuthenticationPattern);
        var build = IndexOf(BuildPattern);

        Assert.True(auth >= 0, "Expected AddAuthentication(...) in Program.cs.");
        Assert.True(build >= 0, "Expected builder.Build() in Program.cs.");
        Assert.True(auth < build,
            "AddAuthentication must be registered before builder.Build().");
    }

    [Fact]
    public void Program_RegistersAuthenticationSchemeHandler()
    {
        // AddAuthentication alone (with no handler) rejects everyone — which
        // closes the surface but makes the API unusable. The preferred fix
        // wires a concrete scheme handler (cookie or JWT, per the finding) so
        // an authenticated principal can actually be established. Accept the
        // two documented examples.
        Assert.True(IndexOf(CookieSchemePattern) >= 0 || IndexOf(JwtSchemePattern) >= 0,
            "Expected AddAuthentication(...) to be chained with a scheme handler " +
            "(.AddCookie(...) or .AddJwtBearer(...)) in Program.cs.");
    }

    // =====================================================================
    // Service registration: authorization
    // =====================================================================

    [Fact]
    public void Program_RegistersAuthorization_OnServicesCollection()
    {
        AssertPresent(AddAuthorizationPattern, "AddAuthorization(...)");
    }

    [Fact]
    public void Program_RegistersAuthorization_BeforeBuild()
    {
        var authz = IndexOf(AddAuthorizationPattern);
        var build = IndexOf(BuildPattern);

        Assert.True(authz >= 0, "Expected AddAuthorization(...) in Program.cs.");
        Assert.True(build >= 0, "Expected builder.Build() in Program.cs.");
        Assert.True(authz < build,
            "AddAuthorization must be registered before builder.Build().");
    }

    // =====================================================================
    // Pipeline middleware: present exactly once
    // =====================================================================

    [Fact]
    public void Program_Pipeline_UsesAuthentication_ExactlyOnce()
    {
        Assert.Equal(1, Count(UseAuthenticationPattern));
    }

    [Fact]
    public void Program_Pipeline_UsesAuthorization_ExactlyOnce()
    {
        Assert.Equal(1, Count(UseAuthorizationPattern));
    }

    // =====================================================================
    // Pipeline middleware: present after Build (i.e. on the app pipeline)
    // =====================================================================

    [Fact]
    public void Program_Pipeline_UseAuthentication_ComesAfterBuild()
    {
        var build = IndexOf(BuildPattern);
        var auth = IndexOf(UseAuthenticationPattern);

        Assert.True(build >= 0 && auth >= 0);
        Assert.True(build < auth,
            "builder.Build() must occur before UseAuthentication() is called on the pipeline.");
    }

    [Fact]
    public void Program_Pipeline_UseAuthorization_ComesAfterBuild()
    {
        var build = IndexOf(BuildPattern);
        var authz = IndexOf(UseAuthorizationPattern);

        Assert.True(build >= 0 && authz >= 0);
        Assert.True(build < authz,
            "builder.Build() must occur before UseAuthorization() is called on the pipeline.");
    }

    // =====================================================================
    // Pipeline ordering — the security-critical part
    // =====================================================================

    [Fact]
    public void Program_Pipeline_UseAuthentication_ComesBeforeUseAuthorization()
    {
        // The authenticated principal must be established by
        // UseAuthentication BEFORE UseAuthorization consults it, otherwise
        // every request is treated as anonymous regardless of credentials.
        var auth = IndexOf(UseAuthenticationPattern);
        var authz = IndexOf(UseAuthorizationPattern);

        Assert.True(auth >= 0, "Expected UseAuthentication() in Program.cs.");
        Assert.True(authz >= 0, "Expected UseAuthorization() in Program.cs.");
        Assert.True(auth < authz,
            "UseAuthentication() must precede UseAuthorization() in the request pipeline.");
    }

    [Fact]
    public void Program_Pipeline_UseAuthorization_ComesBeforeMapControllers()
    {
        // This is the single most important ordering rule for the fix: the
        // authorization middleware MUST run before endpoint routing resolves
        // the request to a controller action, otherwise the [Authorize]
        // attribute on FilesController is never enforced and the whole
        // /api/files/* surface stays open.
        var authz = IndexOf(UseAuthorizationPattern);
        var controllers = IndexOf(MapControllersPattern);

        Assert.True(authz >= 0, "Expected UseAuthorization() in Program.cs.");
        Assert.True(controllers >= 0, "Expected MapControllers() in Program.cs.");
        Assert.True(authz < controllers,
            "UseAuthorization() must precede MapControllers() so the [Authorize] " +
            "attribute is enforced on every /api/files/* endpoint.");
    }

    [Fact]
    public void Program_Pipeline_UseAuthorization_ComesBeforeFallbackAndRun()
    {
        var authz = IndexOf(UseAuthorizationPattern);
        var fallback = IndexOf(FallbackIndexHtmlPattern);
        var run = IndexOf(RunPattern);

        Assert.True(authz >= 0, "Expected UseAuthorization() in Program.cs.");
        Assert.True(fallback >= 0, "Expected MapFallbackToFile(\"index.html\") in Program.cs.");
        Assert.True(run >= 0, "Expected app.Run() in Program.cs.");
        Assert.True(authz < fallback, "UseAuthorization() must precede MapFallbackToFile().");
        Assert.True(authz < run, "UseAuthorization() must precede app.Run().");
    }

    [Fact]
    public void Program_Pipeline_AuthMiddlewareComesBeforeAllEndpoints()
    {
        // Composite check: UseAuthentication < UseAuthorization < MapControllers
        // < MapFallbackToFile < Run, the documented end-to-end ordering.
        var auth = IndexOf(UseAuthenticationPattern);
        var authz = IndexOf(UseAuthorizationPattern);
        var controllers = IndexOf(MapControllersPattern);
        var fallback = IndexOf(FallbackIndexHtmlPattern);
        var run = IndexOf(RunPattern);

        Assert.True(auth >= 0 && authz >= 0 && controllers >= 0 &&
                    fallback >= 0 && run >= 0,
            "All expected authentication/authorization pipeline statements must be present.");

        Assert.True(auth < authz,
            "Order: UseAuthentication must precede UseAuthorization.");
        Assert.True(authz < controllers,
            "Order: UseAuthorization must precede MapControllers.");
        Assert.True(controllers < fallback,
            "Order: MapControllers must precede MapFallbackToFile.");
        Assert.True(fallback < run,
            "Order: MapFallbackToFile must precede Run.");
    }

    // =====================================================================
    // Documentation: the access-control posture must be documented in the
    // README (fix instruction: "Document the chosen posture ... in README.md
    // so the open-by-default behavior is not accidentally deployed").
    // =====================================================================

    [Fact]
    public void Readme_DocumentsAccessControlPosture()
    {
        var readme = SourceFileLoader.LoadAdjacent("README.md");

        var mentionsAccessControl =
            readme.Contains("authoriz", StringComparison.OrdinalIgnoreCase) ||
            readme.Contains("authentication", StringComparison.OrdinalIgnoreCase);

        Assert.True(mentionsAccessControl,
            "README.md must document the access-control posture for the /api/files/* " +
            "surface (e.g. that the API requires authentication/authorization) so the " +
            "open-by-default behavior is not accidentally deployed.");
    }
}

