var source = SourceFileLoader.LoadAdjacent("Controllers", "FilesController.cs");

var docLines = source.Split('\n')
    .Select(l => l.TrimStart())
    .Where(l => l.StartsWith("///"))
    .ToList();

Assert.NotEmpty(docLines);

// IMPORTANT: exclude doc lines that document the file-system exception
// types caught by Execute/ExecuteAsync. The existing comment mentions
// `UnauthorizedAccessException` (an OS-level access-denied exception
// translated into a 400), whose substring "authoriz" would otherwise
// satisfy this check for the wrong reason and hide a missing security
// note. A genuine access-control statement does not reference exception
// types, so filtering them out keeps the assertion meaningful.
var postureLines = docLines
    .Where(l => !l.Contains("Exception", StringComparison.OrdinalIgnoreCase))
    .ToList();

var mentionsAccessControl = postureLines.Any(line =>
    line.Contains("authenticat", StringComparison.OrdinalIgnoreCase) ||
    line.Contains("authoriz", StringComparison.OrdinalIgnoreCase) ||
    line.Contains("access control", StringComparison.OrdinalIgnoreCase) ||
    line.Contains("access-control", StringComparison.OrdinalIgnoreCase));

Assert.True(mentionsAccessControl,
    "The FilesController XML doc comment must document the access-control " +
    "posture (e.g. that the API requires an authenticated/authorized caller). " +
    "Note: references to UnauthorizedAccessException do NOT count, as that is an " +
    "exception type, not an access-control statement.");

