using Microsoft.AspNetCore.Authentication.Cookies;

namespace TestProject {
    public class Program {
        public static void Main(string[] args) {
            var builder = WebApplication.CreateBuilder(args);

            // Add services to the container.

            builder.Services.AddControllers();

            // Security: the /api/files/* surface exposes browse/read/write/delete
            // against the server file system, so it must not be open by default.
            // Wire ASP.NET Core authentication (cookie) and authorization, and
            // protect the controller with [Authorize] (see FilesController).
            builder.Services
                .AddAuthentication(CookieAuthenticationDefaults.AuthenticationScheme)
                .AddCookie();
            builder.Services.AddAuthorization();

            // Bind the FileService configuration section and register the
            // path-safe IFileService implementation so controllers can be
            // activated through dependency injection.
            builder.Services.Configure<TestProject.Configuration.FileServiceOptions>(
                builder.Configuration.GetSection("FileService"));
            builder.Services.AddSingleton<TestProject.Services.IFileService, TestProject.Services.FileService>();

            var app = builder.Build();

            // Configure the HTTP request pipeline.

            app.UseHttpsRedirection();

            app.UseDefaultFiles();

            app.UseStaticFiles();

            // Authentication must precede authorization, and authorization must
            // precede endpoint mapping so [Authorize] is enforced on every route.
            app.UseAuthentication();

            app.UseAuthorization();

            app.MapControllers();

            app.MapFallbackToFile("index.html");

            app.Run();
        }
    }
}

